'use client';
import { useState } from 'react';
import { useStore } from '@/lib/store';
import { Plus, Trash2 } from 'lucide-react';

export default function Dashboard() {
  const [isLogged, setIsLogged] = useState(false);
  const [pass, setPass] = useState('');
  const { members, transactions, addMember, deleteMember, addTransaction, deleteTransaction } = useStore();

  const [newMemberName, setNewMemberName] = useState('');
  const [newMemberAvatar, setNewMemberAvatar] = useState('https://i.pravatar.cc/150?u=');

  const [txType, setTxType] = useState('deposit');
  const [txAmount, setTxAmount] = useState('');
  const [txMember, setTxMember] = useState('');
  const [txDesc, setTxDesc] = useState('');

  const handleLogin = () => {
    if (pass === 'admin123') {
      setIsLogged(true);
    } else {
      alert('পাসওয়ার্ড ভুল! (demo: admin123)');
    }
  };

  if (!isLogged) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900">
        <div className="bg-white p-10 rounded-3xl shadow-2xl text-center max-w-md w-full">
          <h1 className="text-4xl font-bold mb-6">অ্যাডমিন লগইন</h1>
          <input
            type="password"
            placeholder="পাসওয়ার্ড"
            value={pass}
            onChange={(e) => setPass(e.target.value)}
            className="border p-4 rounded-xl w-full text-xl mb-4"
          />
          <button
            onClick={handleLogin}
            className="bg-emerald-600 text-white px-10 py-4 rounded-xl text-xl w-full"
          >
            লগইন
          </button>
          <p className="text-sm text-gray-500 mt-4">demo password: admin123</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-6xl mx-auto">
        <h1 className="text-5xl font-bold mb-10">অ্যাডমিন ড্যাশবোর্ড</h1>

        {/* নতুন সদস্য যোগ */}
        <div className="bg-white p-8 rounded-3xl shadow mb-10">
          <h2 className="text-2xl font-bold mb-4">নতুন সদস্য যোগ করুন</h2>
          <div className="flex flex-col md:flex-row gap-4">
            <input
              placeholder="নাম"
              value={newMemberName}
              onChange={(e) => setNewMemberName(e.target.value)}
              className="border p-4 rounded-xl flex-1"
            />
            <input
              placeholder="ছবির লিংক (optional)"
              value={newMemberAvatar}
              onChange={(e) => setNewMemberAvatar(e.target.value)}
              className="border p-4 rounded-xl flex-1"
            />
            <button
              onClick={() => {
                if (newMemberName.trim()) {
                  addMember(newMemberName.trim(), newMemberAvatar || 'https://i.pravatar.cc/150');
                  setNewMemberName('');
                  setNewMemberAvatar('https://i.pravatar.cc/150?u=');
                }
              }}
              className="bg-emerald-600 text-white px-8 py-4 rounded-xl"
            >
              যোগ করুন
            </button>
          </div>
        </div>

        {/* নতুন লেনদেন */}
        <div className="bg-white p-8 rounded-3xl shadow mb-10">
          <h2 className="text-2xl font-bold mb-4">নতুন লেনদেন যোগ করুন</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <select
              value={txType}
              onChange={(e) => setTxType(e.target.value)}
              className="border p-4 rounded-xl"
            >
              <option value="deposit">জমা (Deposit)</option>
              <option value="expense">খরচ (Expense)</option>
              <option value="donation">দান (Donation)</option>
            </select>

            <input
              type="number"
              placeholder="টাকার পরিমাণ"
              value={txAmount}
              onChange={(e) => setTxAmount(e.target.value)}
              className="border p-4 rounded-xl"
            />

            {txType === 'deposit' && (
              <select
                value={txMember}
                onChange={(e) => setTxMember(e.target.value)}
                className="border p-4 rounded-xl"
              >
                <option value="">সদস্য নির্বাচন করুন</option>
                {members.map((m) => (
                  <option key={m.id} value={m.id}>
                    {m.name}
                  </option>
                ))}
              </select>
            )}

            <input
              placeholder="বিবরণ (যেমন: মাসিক চাঁদা / স্কুল ফি / হাসপাতালে দান)"
              value={txDesc}
              onChange={(e) => setTxDesc(e.target.value)}
              className="border p-4 rounded-xl"
            />

            <button
              onClick={() => {
                if (txAmount && txDesc.trim()) {
                  addTransaction({
                    type: txType,
                    amount: Number(txAmount),
                    memberId: txType === 'deposit' ? txMember : undefined,
                    description: txDesc.trim(),
                  });
                  setTxAmount('');
                  setTxDesc('');
                  setTxMember('');
                } else {
                  alert('টাকা ও বিবরণ দিন');
                }
              }}
              className="bg-emerald-600 text-white py-4 rounded-xl font-bold md:col-span-2"
            >
              লেনদেন যোগ করুন
            </button>
          </div>
        </div>

        {/* সব লেনদেন লিস্ট */}
        <div className="bg-white rounded-3xl shadow p-8">
          <h2 className="text-2xl font-bold mb-6">সব লেনদেন</h2>
          {transactions.length === 0 ? (
            <p className="text-gray-500">কোনো লেনদেন নেই</p>
          ) : (
            transactions.map((t) => (
              <div key={t.id} className="flex justify-between items-center p-5 border-b last:border-0">
                <div>
                  <span className="font-bold">{t.description}</span> • {format(new Date(t.date), 'dd MMM yyyy')}
                </div>
                <div className="flex items-center gap-4">
                  <span className={`font-bold ${t.type === 'deposit' ? 'text-emerald-600' : 'text-red-600'}`}>
                    {t.type === 'deposit' ? '+' : '-'}৳{t.amount.toLocaleString()}
                  </span>
                  <button onClick={() => deleteTransaction(t.id)} className="text-red-500 hover:text-red-700">
                    <Trash2 size={20} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}